  'ref.linkExplain': { fr: "Toute personne qui s'inscrit via ce lien devient votre <strong>filleul</strong>. Vous touchez <strong>10 %</strong> de la part EduWeb dès qu'un filleul <strong>paie un coach</strong> (parent) ou <strong>accepte une mission</strong> (coach).", en: "Anyone who signs up via this link becomes your <strong>referral</strong>. You earn <strong>10%</strong> of EduWeb's share as soon as a referral <strong>pays for a coach</strong> (parent) or <strong>accepts an assignment</strong> (coach).", ar: 'كل من يسجّل عبر هذا الرابط يصبح <strong>مُحالًا</strong> لك. تحصل على <strong>10%</strong> من حصّة EduWeb بمجرد أن <strong>يدفع مُحال لمدرّب</strong> (ولي أمر) أو <strong>يقبل مهمة</strong> (مدرّب).', es: 'Cualquiera que se registre con este enlace se convierte en tu <strong>referido</strong>. Ganas el <strong>10 %</strong> de la parte de EduWeb en cuanto un referido <strong>paga a un coach</strong> (padre) o <strong>acepta una misión</strong> (coach).', ko: '이 링크로 가입한 사람은 당신의 <strong>추천인</strong>이 됩니다. 추천인이 <strong>코치에게 결제</strong>(학부모)하거나 <strong>미션을 수락</strong>(코치)하면 EduWeb 수익의 <strong>10%</strong>를 받습니다.', zh: '任何通过此链接注册的人都会成为您的<strong>推荐对象</strong>。当推荐对象<strong>为教练付款</strong>（家长）或<strong>接受任务</strong>（教练）时，您即可获得 EduWeb 收益的 <strong>10%</strong>。', ru: 'Каждый, кто зарегистрируется по этой ссылке, становится вашим <strong>рефералом</strong>. Вы получаете <strong>10%</strong> от доли EduWeb, как только реферал <strong>оплачивает коуча</strong> (родитель) или <strong>принимает задание</strong> (коуч).', uk: "Кожен, хто зареєструється за цим посиланням, стає вашим <strong>рефералом</strong>. Ви отримуєте <strong>10%</strong> від частки EduWeb, щойно реферал <strong>оплачує коуча</strong> (батьки) або <strong>приймає завдання</strong> (коуч)." },
  'ref.shareWhatsApp': { fr: 'Partager sur WhatsApp', en: 'Share on WhatsApp', ar: 'مشاركة عبر واتساب', es: 'Compartir por WhatsApp', ko: '왓츠앱으로 공유', zh: '分享到 WhatsApp', ru: 'Поделиться в WhatsApp', uk: 'Поділитися у WhatsApp' },
  'ref.shareEmail': { fr: 'Partager par email', en: 'Share by email', ar: 'مشاركة بالبريد', es: 'Compartir por email', ko: '이메일로 공유', zh: '通过邮件分享', ru: 'Поделиться по эл. почте', uk: 'Поділитися ел. поштою' },
  'ref.inviteMsg': { fr: 'Rejoins EduWeb via mon lien : ', en: 'Join EduWeb via my link: ', ar: 'انضمّ إلى EduWeb عبر رابطي: ', es: 'Únete a EduWeb con mi enlace: ', ko: '내 링크로 EduWeb에 가입하세요: ', zh: '通过我的链接加入 EduWeb： ', ru: 'Присоединяйся к EduWeb по моей ссылке: ', uk: 'Приєднуйся до EduWeb за моїм посиланням: ' },
  'ref.inviteSubject': { fr: 'Rejoins EduWeb', en: 'Join EduWeb', ar: 'انضمّ إلى EduWeb', es: 'Únete a EduWeb', ko: 'EduWeb에 가입하세요', zh: '加入 EduWeb', ru: 'Присоединяйся к EduWeb', uk: 'Приєднуйся до EduWeb' },
  'ref.inviteBody': { fr: 'Inscris-toi sur EduWeb via mon lien : ', en: 'Sign up to EduWeb via my link: ', ar: 'سجّل في EduWeb عبر رابطي: ', es: 'Regístrate en EduWeb con mi enlace: ', ko: '내 링크로 EduWeb에 가입하세요: ', zh: '通过我的链接注册 EduWeb： ', ru: 'Зарегистрируйся в EduWeb по моей ссылке: ', uk: 'Зареєструйся в EduWeb за моїм посиланням: ' },
  'ref.myReferrals': { fr: 'Mes filleuls', en: 'My referrals', ar: 'مُحالوني', es: 'Mis referidos', ko: '내 추천인', zh: '我的推荐', ru: 'Мои рефералы', uk: 'Мої реферали' },
  'ref.noReferral': { fr: "Aucun filleul pour l'instant. Partagez votre lien pour commencer à gagner.", en: 'No referrals yet. Share your link to start earning.', ar: 'لا مُحالين حتى الآن. شارك رابطك لتبدأ الربح.', es: 'Aún no hay referidos. Comparte tu enlace para empezar a ganar.', ko: '아직 추천인이 없습니다. 링크를 공유해 수익을 시작하세요.', zh: '暂无推荐。分享您的链接即可开始赚取。', ru: 'Рефералов пока нет. Поделитесь ссылкой, чтобы начать зарабатывать.', uk: 'Рефералів поки немає. Поділіться посиланням, щоб почати заробляти.' },
  'ref.referral': { fr: 'Filleul', en: 'Referral', ar: 'المُحال', es: 'Referido', ko: '추천인', zh: '推荐对象', ru: 'Реферал', uk: 'Реферал' },
  'ref.registeredOn': { fr: 'Inscrit le', en: 'Registered on', ar: 'تاريخ التسجيل', es: 'Registrado el', ko: '가입일', zh: '注册于', ru: 'Зарегистрирован', uk: 'Зареєстрований' },
  'ref.missionsEarnings': { fr: 'Missions abouties & gains', en: 'Completed assignments & earnings', ar: 'المهام المنجزة والأرباح', es: 'Misiones completadas y ganancias', ko: '완료된 미션 및 수익', zh: '已完成任务与收益', ru: 'Завершённые задания и доходы', uk: 'Завершені завдання та доходи' },
  'ref.total': { fr: 'Total', en: 'Total', ar: 'الإجمالي', es: 'Total', ko: '합계', zh: '合计', ru: 'Итого', uk: 'Разом' },
  'ref.noEarning': { fr: "Aucun gain pour l'instant. Vos commissions apparaîtront ici dès qu'un filleul conclut une action.", en: 'No earnings yet. Your commissions will appear here as soon as a referral completes an action.', ar: 'لا أرباح حتى الآن. ستظهر عمولاتك هنا بمجرد أن يُكمل مُحال إجراءً.', es: 'Aún no hay ganancias. Tus comisiones aparecerán aquí en cuanto un referido complete una acción.', ko: '아직 수익이 없습니다. 추천인이 행동을 완료하면 커미션이 여기에 표시됩니다.', zh: '暂无收益。当推荐对象完成操作后，您的佣金将在此显示。', ru: 'Доходов пока нет. Ваши комиссии появятся здесь, как только реферал совершит действие.', uk: "Доходів поки немає. Ваші комісії з'являться тут, щойно реферал виконає дію." },
  'ref.yourCommission': { fr: 'Votre commission (10 %)', en: 'Your commission (10%)', ar: 'عمولتك (10%)', es: 'Tu comisión (10 %)', ko: '내 커미션 (10%)', zh: '您的佣金（10%）', ru: 'Ваша комиссия (10%)', uk: 'Ваша комісія (10%)' },
  'ref.settlement': { fr: 'Règlement', en: 'Payment', ar: 'التسوية', es: 'Liquidación', ko: '정산', zh: '结算', ru: 'Выплата', uk: 'Виплата' },
