  'ref.typePaid': { fr: 'A payé un coach', en: 'Paid for a coach', ar: 'دفع لمدرّب', es: 'Pagó a un coach', ko: '코치에게 결제함', zh: '已为教练付款', ru: 'Оплатил коуча', uk: 'Оплатив коуча' },
