  'cprofil.doc.cni': { fr: "Pièce d'identité (CNI / passeport)", en: 'ID document (ID card / passport)', ar: 'وثيقة هوية (بطاقة / جواز سفر)', es: 'Documento de identidad (DNI / pasaporte)', ko: '신분증 (주민증 / 여권)', zh: '身份证件（身份证 / 护照）', ru: 'Удостоверение личности (паспорт)', uk: 'Посвідчення особи (паспорт)' },
