  'cprofil.doc.certificat': { fr: 'Certificat / Attestation', en: 'Certificate / Attestation', ar: 'شهادة / إفادة', es: 'Certificado / Acreditación', ko: '증명서', zh: '证书 / 证明', ru: 'Сертификат / справка', uk: 'Сертифікат / довідка' },
  'cprofil.doc.certificatHint': { fr: 'Formations, expériences (optionnel)', en: 'Training, experience (optional)', ar: 'تدريبات وخبرات (اختياري)', es: 'Formaciones, experiencias (opcional)', ko: '교육·경력 (선택)', zh: '培训、经历（可选）', ru: 'Обучение, опыт (необязательно)', uk: "Навчання, досвід (необов'язково)" },
