  'cprofil.docsFormats': { fr: 'Formats acceptés : PDF, image ou Word — max 25 Mo par fichier.', en: 'Accepted formats: PDF, image or Word — max 25 MB per file.', ar: 'الصيغ المقبولة: PDF أو صورة أو Word — 25 م.ب كحد أقصى لكل ملف.', es: 'Formatos aceptados: PDF, imagen o Word — máx. 25 MB por archivo.', ko: '허용 형식: PDF, 이미지 또는 Word — 파일당 최대 25MB.', zh: '接受格式：PDF、图片或 Word — 每个文件最大 25 MB。', ru: 'Допустимые форматы: PDF, изображение или Word — макс. 25 МБ на файл.', uk: 'Допустимі формати: PDF, зображення або Word — макс. 25 МБ на файл.' },
  'cprofil.presBanner': { fr: 'Un texte est <strong>généré automatiquement</strong> à partir de votre profil (« en référence au CV »). Vous pouvez le modifier librement.', en: 'A text is <strong>automatically generated</strong> from your profile (based on your CV). You can edit it freely.', ar: 'يُنشأ نص <strong>تلقائيًا</strong> من ملفك (استنادًا إلى سيرتك). يمكنك تعديله بحرية.', es: 'Se <strong>genera automáticamente</strong> un texto a partir de tu perfil (según tu CV). Puedes modificarlo libremente.', ko: '프로필(이력서 기반)에서 텍스트가 <strong>자동 생성</strong>됩니다. 자유롭게 수정하세요.', zh: '系统会根据您的资料（参考简历）<strong>自动生成</strong>文本。您可自由修改。', ru: 'Текст <strong>генерируется автоматически</strong> из вашего профиля (по резюме). Вы можете свободно его изменить.', uk: 'Текст <strong>генерується автоматично</strong> з вашого профілю (за резюме). Ви можете вільно його змінити.' },
  'cprofil.bio': { fr: 'Bio / Méthodologie', en: 'Bio / Methodology', ar: 'نبذة / منهجية', es: 'Bio / Metodología', ko: '소개 / 방법론', zh: '简介 / 方法', ru: 'О себе / Методика', uk: 'Про себе / Методика' },
